import React, { useState, useEffect } from 'react';
import { Outlet, NavLink, useNavigate } from 'react-router-dom';
import { useDispatch, useSelector } from 'react-redux';
import { logout } from '../../store/slices/authSlice';
import toast from 'react-hot-toast';

const NAV = [
  { section:'Overview', items:[
    { to:'/', label:'Dashboard', icon:'🏠', end:true },
  ]},
  { section:'Admissions', items:[
    { to:'/enquiry',      label:'Enquiry',      icon:'📞' },
    { to:'/registration', label:'Registration', icon:'📄' },
    { to:'/students',     label:'Students',     icon:'👨‍🎓' },
  ]},
  { section:'Academic', items:[
    { to:'/attendance',        label:'Mark Attendance',   icon:'✅' },
    { to:'/attendance-report', label:'Attendance Report', icon:'📋' },
    { to:'/exams',             label:'Examinations',      icon:'📝' },
    { to:'/timetable',         label:'Timetable',         icon:'📅' },
  ]},
  { section:'Finance', items:[
    { to:'/fees',     label:'Fee Management', icon:'💰' },
    { to:'/expenses', label:'Expenses',       icon:'📊' },
  ]},
  { section:'Staff & Infra', items:[
    { to:'/employees', label:'Employees', icon:'👥' },
    { to:'/transport', label:'Transport', icon:'🚌' },
    { to:'/library',   label:'Library',   icon:'📖' },
  ]},
  { section:'Communication', items:[
    { to:'/notices', label:'Notice Board', icon:'📢' },
  ]},
  { section:'Analytics', items:[
    { to:'/reports',  label:'Reports',  icon:'📈' },
    { to:'/settings', label:'Settings', icon:'⚙️' },
  ]},
];

export default function Layout() {
  const dispatch   = useDispatch();
  const navigate   = useNavigate();
  const user       = useSelector(s => s.auth.user);
  const [collapsed, setCollapsed] = useState(false);
  const [settings,  setSettings]  = useState(() => {
    try { return JSON.parse(localStorage.getItem('school_settings')) || {}; } catch { return {}; }
  });

  useEffect(() => {
    const handler = () => {
      try { setSettings(JSON.parse(localStorage.getItem('school_settings')) || {}); } catch {}
    };
    window.addEventListener('school_settings_updated', handler);
    return () => window.removeEventListener('school_settings_updated', handler);
  }, []);

  const sidebarBg  = settings.primaryColor || '#1E1B4B';
  const schoolName = settings.schoolName   || 'EduErpee';
  const logo       = settings.logo         || '';

  const handleLogout = async () => {
    await dispatch(logout());
    toast.success('Logged out');
    navigate('/login');
  };

  const initials = (user?.fullName || user?.full_name || 'U').split(' ').map(w=>w[0]).join('').slice(0,2).toUpperCase();

  return (
    <div style={{display:'flex',height:'100vh',overflow:'hidden',fontFamily:'Plus Jakarta Sans, sans-serif'}}>

      {/* SIDEBAR */}
      <aside style={{width:collapsed?52:232,background:sidebarBg,display:'flex',flexDirection:'column',flexShrink:0,overflow:'hidden',transition:'width .25s cubic-bezier(.4,0,.2,1)'}}>
        {/* Brand */}
        <div style={{height:52,display:'flex',alignItems:'center',gap:10,padding:'0 12px',borderBottom:'1px solid rgba(255,255,255,.1)',flexShrink:0}}>
          <div style={{width:30,height:30,borderRadius:8,background:'linear-gradient(135deg,#A78BFA,#F59E0B)',display:'flex',alignItems:'center',justifyContent:'center',fontSize:15,flexShrink:0,overflow:'hidden'}}>
            {logo ? <img src={logo} alt="logo" style={{width:'100%',height:'100%',objectFit:'cover'}}/> : '🎓'}
          </div>
          {!collapsed&&<div>
            <div style={{fontSize:14,fontWeight:800,color:'#fff',whiteSpace:'nowrap'}}>{schoolName}</div>
            <div style={{fontSize:9,color:'rgba(255,255,255,.4)',textTransform:'uppercase',letterSpacing:'.08em'}}>School ERP</div>
          </div>}
        </div>

        {/* User */}
        {!collapsed&&(
          <div style={{padding:'10px 12px',borderBottom:'1px solid rgba(255,255,255,.1)',display:'flex',alignItems:'center',gap:8,flexShrink:0}}>
            <div style={{width:28,height:28,borderRadius:7,background:'linear-gradient(135deg,#A78BFA,#F59E0B)',display:'flex',alignItems:'center',justifyContent:'center',fontSize:11,fontWeight:700,color:'#fff',flexShrink:0}}>{initials}</div>
            <div style={{overflow:'hidden'}}>
              <div style={{fontSize:12,fontWeight:600,color:'#fff',whiteSpace:'nowrap',overflow:'hidden',textOverflow:'ellipsis'}}>{user?.fullName||user?.full_name||'User'}</div>
              <div style={{fontSize:10,color:'rgba(255,255,255,.4)',textTransform:'capitalize'}}>{user?.role?.replace('_',' ')}</div>
            </div>
          </div>
        )}

        {/* Nav */}
        <nav style={{flex:1,overflowY:'auto',overflowX:'hidden',padding:'6px 0'}}>
          {NAV.map(({section,items})=>(
            <div key={section}>
              {!collapsed&&<div style={{padding:'10px 12px 3px',fontSize:9,fontWeight:700,color:'rgba(255,255,255,.3)',letterSpacing:'.12em',textTransform:'uppercase'}}>{section}</div>}
              {items.map(item=>(
                <NavLink key={item.to} to={item.to} end={item.end}
                  style={({isActive})=>({
                    display:'flex',alignItems:'center',gap:9,
                    padding:collapsed?'9px 0':'8px 12px',
                    justifyContent:collapsed?'center':'flex-start',
                    color:isActive?'#fff':'rgba(255,255,255,.55)',
                    fontSize:12,fontWeight:isActive?700:400,
                    borderLeft:`2px solid ${isActive?'#A78BFA':'transparent'}`,
                    background:isActive?'rgba(255,255,255,.12)':'transparent',
                    textDecoration:'none',transition:'all .12s',
                    whiteSpace:'nowrap',overflow:'hidden',
                  })}
                  title={collapsed?item.label:''}>
                  <span style={{fontSize:15,flexShrink:0}}>{item.icon}</span>
                  {!collapsed&&item.label}
                </NavLink>
              ))}
            </div>
          ))}
        </nav>

        {/* Logout */}
        <div style={{padding:'10px 12px',borderTop:'1px solid rgba(255,255,255,.1)',flexShrink:0}}>
          <button onClick={handleLogout} style={{width:'100%',padding:collapsed?'8px 0':'8px',border:'1px solid rgba(255,255,255,.2)',borderRadius:8,background:'transparent',color:'rgba(255,255,255,.6)',fontSize:12,cursor:'pointer',display:'flex',alignItems:'center',justifyContent:collapsed?'center':'flex-start',gap:7}}>
            <span>🚪</span>{!collapsed&&'Logout'}
          </button>
        </div>
      </aside>

      {/* MAIN */}
      <main style={{flex:1,display:'flex',flexDirection:'column',overflow:'hidden'}}>
        <header style={{height:52,background:'#fff',borderBottom:'0.5px solid #E5E7EB',display:'flex',alignItems:'center',gap:12,padding:'0 20px',flexShrink:0}}>
          <button onClick={()=>setCollapsed(!collapsed)} style={{background:'none',border:'none',cursor:'pointer',fontSize:18,color:'#6B7280',padding:'4px',borderRadius:6}}>☰</button>
          <div style={{flex:1}}/>
          <div style={{fontWeight:700,fontSize:13,color:'#1E1B4B'}}>{schoolName}</div>
          <div style={{width:1,height:22,background:'#E5E7EB'}}/>
          <div style={{display:'flex',alignItems:'center',gap:8}}>
            <div style={{width:28,height:28,borderRadius:7,background:'linear-gradient(135deg,#A78BFA,#F59E0B)',display:'flex',alignItems:'center',justifyContent:'center',fontSize:11,fontWeight:700,color:'#fff'}}>{initials}</div>
            <span style={{fontSize:12,fontWeight:600,color:'#374151'}}>{(user?.fullName||user?.full_name||'User').split(' ')[0]}</span>
          </div>
        </header>
        <div style={{flex:1,overflowY:'auto',padding:20,background:'#F9FAFB'}}>
          <Outlet />
        </div>
      </main>
    </div>
  );
}
